var e=JSON.parse(`[{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"뭘 하고 있었지?","JPN":"何をしていたんだ？","ENG":"What was I doing?","TWN":"我在做什麼？"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"나는 왜, 이런 곳에…….","JPN":"私はどうして、こんなところに……","ENG":"Why am I... in a place like this...?","TWN":"我怎麼會在這裡……"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"하하. 하하…!","JPN":"ハハ。ハハハ…！","ENG":"Haha. Haha...!","TWN":"哈哈，哈哈…！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"그래. 아무도 <color=#ffd34c>우리</color>를 이해하지 못해.","JPN":"そう。誰も<color=#ffd34c>私たち</color>のことを理解できない。","ENG":"Yeah. No one will understand <color=#ffd34c>us</color>.","TWN":"沒錯，沒有人理解<color=#ffd34c>我們</color>。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"이곳에서는 슬픔도, 원한도, 고통도, 아무것도 존재하지 않아.","JPN":"ここには悲しみも、恨みも、苦しみも、何も存在しない。","ENG":"Nothing exists here. Not even sorrow, resentment, or pain.","TWN":"在這裡，傷心、憎恨、痛苦，這些都不存在。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"아아, 이런 황홀한 기분을 느낄 수 있을 줄이야…!","JPN":"ああ、こんなうっとりとした気分を味わえるなんて……！","ENG":"Ahh, I never knew I could feel this ecstatic...!","TWN":"啊～沒想到可以感受到如此豐富的情緒…！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"이런, 감정에 도취한 나머지 못 볼 꼴을 보인 것 같구나.","JPN":"おっと、感情に溺れて見にくい姿を見せてしまったようだ。","ENG":"Oh, I'm embarrassed to show you how emotionally high I was.","TWN":"糟糕，真是失態，竟然讓人看到我如此陶醉的樣子。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"걱정하지 마렴. 네가 누군진 모르겠지만, 곧 나와 같이 아무런 걱정도 없게 해줄게.","JPN":"心配するな。お前が誰なのかはわからないが、すぐ私みたいに何の心配もないようにしてやる。","ENG":"No worries. I don't know who you are, but I'll make your worries go away, just like me.","TWN":"放心，我不知道你是誰，但我現在就可以讓你和我一起脫離一切的煩惱。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"아무런… 걱정도… 없…","JPN":"何の……心配……も……","ENG":"Make... your worries...","TWN":"脫離…一切的…"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"이…?","JPN":"な……？","ENG":"go away...?","TWN":"煩惱…？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"빌어먹을. 하루 세끼 풀죽은 대체 누구 머리에서 나온 아이디어야?","JPN":"くそ。三食お粥って、誰のアイデアだ？","ENG":"Ugh. Whose idea was it to eat grass porridge for every meal?","TWN":"該死，到底是誰想到一天三餐都吃野菜粥的？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"엥? 맛이 없었나요? 간은 분명 딱 맞았는데!","JPN":"えっ？　まずいですか？　塩かげんはちょうど良かったんですけど！","ENG":"Huh? Does it taste bad? I seasoned it and all!","TWN":"嗯？不好吃嗎？我明明有加鹽巴呀！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"간이고 자시고 네가 쓸데없는 부품을 산 탓이잖아. 망할 꼬맹이.","JPN":"塩かげんも何も、お前がくだらない部品を買うからだろう。クソガキ。","ENG":"Who cares about seasoning? This is all because you bought those useless parts, you brat.","TWN":"重點不是有沒有調味，重點是配菜的問題，臭小鬼。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FOOLSDAY_HORIZON_NULL_NULL","text":{"KOREA":"반찬 투정은 삼가십시오, 리타. 나이도 먹을 만큼 먹지 않았습니까.","JPN":"ご飯の文句は止してください、リタ。もういい年ではありませんか。","ENG":"Stop complaining about your food, Rita. I thought you were more mature than that.","TWN":"不要挑食，麗塔。都已經這麼大年紀還嫌東嫌西的。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"FOOLSDAY_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FOOLSDAY_HORIZON_NULL_NULL","text":{"KOREA":"미뢰를 통한 무의미한 정보 전달에 구애받지 않는다는 건 큰 장점입니다.","JPN":"味蕾という無意味な情報提供の手段にとらわれないということは大きな長所です。","ENG":"It has the enormous benefit of not being limited by meaningless information delivered via taste buds.","TWN":"野菜粥最大的優點，就是可以跳脫味蕾的限制。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"FOOLSDAY_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"아, 맞다! 대표님 서랍에 있던 작은 상자, 위험한 물건 같길래 버렸어요!","JPN":"あっ、そうだ！　代表の引き出しにあった小さな箱、危ないものみたいだから捨てました！","ENG":"Oh, right! Boss, the tiny box you had in your drawer, I threw it away because it seemed dangerous!","TWN":"對了！BOSS，你抽屜裡有個小箱子，感覺好像是什麼危險物品，我就把它丟掉囉！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"미끌미끌거리던데 저 잘했죠?","JPN":"ぬるぬるしてましたけど、よくやったでしょう？","ENG":"It was all slippery. Did I do a good job?","TWN":"整個都油油的，我很棒吧？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FOOLSDAY_HORIZON_NULL_NULL","text":{"KOREA":"……윤활유 값은 ■■ 월급에서 까겠습니다.","JPN":"……潤滑油のお代は、■■の給料から引くことにします。","ENG":"...I'll deduct the cost of the lubricants from ■■■■'s salary.","TWN":"……潤滑油的錢會從■■的薪水裡面扣。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"FOOLSDAY_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"댕-!","JPN":"ガーン！","ENG":"DUN-!","TWN":"噹-！"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};